#include "CurvatureADCLP.h" // <-- NOTE THIS FILE WAS AUTO GENERATED by GENERATECLP()

// itk
#include <itkCurvatureAnisotropicDiffusionImageFilter.h>
#include <itkImageFileWriter.h>
#include <itkImageFileReader.h>
#include <itkSubtractImageFilter.h>

int main (int argc, char * argv[])
{
  PARSE_ARGS;

  std::cout << "The input volume is: " << inputVolume << std::endl;
  std::cout << "The output volume is: " << outputVolume << std::endl;
  std::cout << "conductance: " << conductance << std::endl;
  std::cout << "time step: " << timeStep << std::endl;
  std::cout << "iterations: " << iterations << std::endl;

  using PixelType = float;
  constexpr int Dimension = 3;
  using ImageType = itk::Image<PixelType, Dimension>;

  using ReaderType = itk::ImageFileReader<ImageType>;
  auto reader = ReaderType::New();

  reader->SetFileName(inputVolume);

  using FilterType = itk::CurvatureAnisotropicDiffusionImageFilter<ImageType, ImageType>;
  auto filter = FilterType::New();
  filter->SetInput(reader->GetOutput());
  filter->SetConductanceParameter(conductance);
  filter->SetTimeStep(timeStep);
  filter->SetNumberOfIterations(iterations);


  using WriterType = itk::ImageFileWriter<ImageType>;
  auto writer = WriterType::New();

  writer->SetInput(filter->GetOutput());
  writer->SetFileName(outputVolume);

  try {
    writer->Update();
  }
  catch(const itk::ExceptionObject e){
    std::cout << "I DONT WORK AHHH ITS BECAUSE: " << e << std::endl;
    return EXIT_FAILURE;
  }

  return EXIT_SUCCESS;
}
